end-pr;

//  Returns a new list signature.
dcl-pr Signature_new likeds(signature_t) extproc('Signature_new');
end-pr;

//  Checks, whether a given handle is a valid list handle, or not.
dcl-pr checkListHandle extproc('checkListHandle');
