//  Parsed URL
dcl-ds parsedUrl_t len(512) qualified based(pDummy);
  type     char(10);
  pos      uns(5);
  protocol likeds(substr_t);
  host     likeds(substr_t);
  port     likeds(substr_t);
  file     likeds(substr_t);
  path     likeds(substr_t);
  query    likeds(substr_t);
  data     like(url_t);
end-ds;

//  For internal use only
