  end-pi;

  //  Return value
  dcl-s port int(10) inz;

  //  Parameter positions
  dcl-c p_rc 2;

  //  Fields for optional parameters
  dcl-s rc int(10) inz;

  //  Helper fields
  dcl-s isPresent int(10) inz;
  dcl-ds parsedUrl likeds(parsedUrl_t) inz;
