//  Get application message file name
dcl-pr lf_getAppMsgFileName char(10);
end-pr;

//  Get application message file library name
dcl-pr lf_getAppMsgFileLibrary char(10);
end-pr;

//  Set application message file name
dcl-pr lp_setAppMsgFileName;
  i_file char(10) const;
end-pr;

//  Set application message file library name
dcl-pr lp_setAppMsgFileLibrary;
  i_lib char(10) const;
end-pr;

//  Retrieve message description
dcl-pr lf_rtvMsgD pointer;
  i_format     char(8) const;
  i_msgID      char(7) const;
  i_rplData    varchar(4096) const;
  i_qMsgF      likeds(qObj_t) const;
  o_msg        likeds(msg_t);
  i_rplVars    char(10) options(*nopass) const;
  i_rtnCtrlChr char(10) options(*nopass) const;
end-pr;

// -----------------------------------------
//  Global constants
// -----------------------------------------

// -----------------------------------------
//  Global fields
// -----------------------------------------
dcl-ds g_qAppMsgFile likeds(qObj_t) inz;

//=======================================================================
//  Sets the application message file.
//=======================================================================
//  Parameters:
//   i_file        - The name of the message file.
//                   Default:        QCPFMSG
//   i_lib         - The name of the message file library.
//                   Default:        *LIBL
//
//  Returns:
//   void
//=======================================================================
dcl-proc p_setAppMsgFile export;
  dcl-pi *n;
    i_file char(10) options(*nopass) const;
    i_lib  char(10) options(*nopass) const;
  end-pi;

  //  Parameter positions
  dcl-c p_file 1;
  dcl-c p_lib 2;

  //  Optional parameter fields
  dcl-s file like(i_file) inz;
  dcl-s lib like(i_lib) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  //-------------------------------------------------------------------*

  // Process optional parameter values ...
  // ... file
  if   %parms >= p_file;
    CEETSTA(isPresent: p_file: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    file = i_file;
  else;
    file = 'QCPFMSG';
  endif;

  // ... library
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_lib: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    lib = i_lib;
  else;
    lib = '*LIBL';
  endif;

  // Set the message file ...
  lp_setAppMsgFileName(file);
  lp_setAppMsgFileLibrary(lib);

  return;


end-proc;

//=========================================================================
//  Creates a new message.
//=========================================================================
//  Parameters:
//   i_ID          - The message ID.
//                   Default:        cMSG_ID_NONE (if omitted)
//                                   cMSG_ID_NULL (if not passed)
//                   cMsg_ID_OK    - An OK message which actually is
//                                   a blank message structure.
//                   cMsg_ID_NONE  - A message with no message ID,
//                                   just message text.
//                   cMsg_ID_NULL  - A NULL message.
//   i_data        - The message data of the replacement variables.
//                   Default:        *BLANKS
//   i_type        - The message type.
//                   Default:        cMsg_Info
//                   Please refer to PBASICS1R1 for a list of valid
//                   message types.
//   i_file        - The message file that contains the message ID.
//                   Default:        The application message file.
//   i_lib         - The message file library.
//                   Default:        The application message file
//                                   library.
//
//  Returns:
//   void
//=========================================================================
dcl-proc f_newMsg export;
  dcl-pi *n likeds(msg_t);
    i_ID   like(msg_t.id) options(*omit: *nopass) const;
    i_data varchar(512) options(*omit: *nopass) const;
    i_type like(msg_t.type) options(*omit: *nopass) const;
    i_file like(msg_t.file) options(*omit: *nopass) const;
    i_lib  like(msg_t.lib) options(*omit: *nopass) const;
  end-pi;

  //  Return value
  dcl-ds msg likeds(msg_t) inz;

  //  Parameter positions
  dcl-c p_ID 1;
  dcl-c p_data 2;
  dcl-c p_type 3;
  dcl-c p_file 4;
  dcl-c p_lib 5;

  //  Optional parameter fields
  dcl-s ID like(i_ID) inz;
  dcl-s data like(i_data) inz;
  dcl-s type like(i_type) inz;
  dcl-s file like(i_file) inz;
  dcl-s lib like(i_lib) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  // ---------------------------------------------------------

  // Process optional parameter values ...
  // ... ID
  if  %parms >= p_ID;
    CEETSTA(isPresent: p_ID: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    ID = i_ID;
  else;
    if  %parms >= p_ID;
      ID = cMSG_ID_NONE;
    else;
      ID = cMSG_ID_NULL;
    endif;
  endif;

  // ... Data
  if  %parms >= p_data;
    CEETSTA(isPresent: p_data: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    data = i_data;
  else;
    data = '';
  endif;

  // ... Type
  if  %parms >= p_type;
    CEETSTA(isPresent: p_type: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    type = i_type;
  else;
    if   (ID <> cMsg_ID_OK  ) and
         (ID <> cMsg_ID_NULL);
      type = cMsg_Info;
    else;
      type = '';
    endif;
  endif;

  // ... File
  if  %parms >= p_file;
    CEETSTA(isPresent: p_file: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    file = i_file;
  else;
    file = lf_getAppMsgFileName();
  endif;

  // ... Library
  if  %parms >= p_lib;
    CEETSTA(isPresent: p_lib: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    lib = i_lib;
  else;
    lib = lf_getAppMsgFileLibrary();
  endif;

  // Check dependencies ...
  if   (ID = cMSG_ID_NONE) and (data = '');
    p_assert(cFalse:
             'Message data must not be *BLANKS in case that -
               message ID is specified as cMsg_ID_NONE.'           );
  endif;

  // Produce message ...
  clear   msg;

  msg.ID   = ID;
  if   msg.ID <> cMSG_ID_NULL;
    msg.data = data;
    msg.type = type;
    msg.file = file;
    msg.lib  = lib;
  endif;

  return   msg;


end-proc;

//=========================================================================
//  Sends a program message.
//=========================================================================
//  Parameters:
//   i_msg         - The message to send.
//   i_toStkC      - The stack entry to send the message to.
//                   Default:        cMsg_Same
//                   cMsg_Ext      - The external message queue.
//                   cMsg_Prv      - The procedure that is before
//                                   the procdure that is specified
//                                   at i_toProc.
//                   cMsg_Same     - The procedure that is specified
//                                   at i_toProc.
//   i_toProc      - The procedure to send the message to.
//                   Default:        cMsg_ToMyself
//                   cMsg_ToMyself - The procedure that calls
//                                   f_sndPgmMsg().
//                   cMsg_ToPgmBdy - The program boundary.
//                   cMsg_ToCtlBdy - The control boundary.
//                   cMsg_ToPgm    - The program specified
//                                   at i_toPgm.
//   i_toMod       - The module that contains the procedure.
//                   Default:        *NONE
//   i_toPgm       - The program that contains the module.
//                   Default:        *NONE
//   o_msg         - The API error message.
//
//  Returns:
//   msgKey        - The message key of the message sent.
//=========================================================================
dcl-proc f_sndPgmMsg export;
  dcl-pi *n char(4);
    i_msg    likeds(msg_t) const;
    i_toStkC int(10) options(*nopass: *omit) const;
    i_toProc char(256) options(*nopass: *omit) const;
    i_toMod  char(10) options(*nopass: *omit) const;
    i_toPgm  char(10) options(*nopass: *omit) const;
    o_msg    likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-s msgKey char(4) inz;

  //  Parameter positions
  dcl-c p_toStkC 2;
  dcl-c p_toProc 3;
  dcl-c p_toMod 4;
  dcl-c p_toPgm 5;
  dcl-c p_msg 6;

  //  Optional parameter fields
  dcl-s toStkC like(i_toStkC) inz;
  dcl-s toProc like(i_toProc) inz;
  dcl-s toMod like(i_toMod) inz;
  dcl-s toPgm like(i_toPgm) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;

  //  Helper fields QMHSNDPM
  dcl-ds qMsgF likeds(qObj_t) inz;
  dcl-s callStkE like(i_toProc) inz;
  dcl-s callStkCtr int(10) inz;
  dcl-ds callStkEQ qualified;
    module  char(10) inz;
    program char(10) inz;
  end-ds;
  dcl-ds errCode likeds(errCode_t) inz;
  //-------------------------------------------------------------------*

  // Process optional parameter values ...
  // ... stack counter
  if  %parms >= p_toStkC;
    CEETSTA(isPresent: p_toStkC: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    toStkC = i_toStkC;
  else;
    toStkC = cMsg_Same;
  endif;

  // ... to procedure
  if  %parms >= p_toProc;
    CEETSTA(isPresent: p_toProc: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    toProc = i_toProc;
  else;
    toProc = cMsg_toMySelf;
  endif;

  // ... to module
  if  %parms >= p_toMod;
    CEETSTA(isPresent: p_toMod: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    toMod  = i_toMod;
  else;
    toMod  = '*NONE';
  endif;

  // ... to program
  if  %parms >= p_toPgm;
    CEETSTA(isPresent: p_toPgm: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    toPgm  = i_toPgm;
  else;
    toPgm  = '*NONE';
  endif;

  // Check dependencies ...
  p_assert(i_msg.ID <> cMSG_ID_OK     and
           i_msg.ID <> cMSG_ID_NULL         :
           'Message ID must not be ''' + i_msg.ID + '''.'   );

  // Set values to call QMHSNDPM API:
  // Call stack counter ...
  select;
  // ... *EXT
  when   toStkC = cMsg_Ext;
    callStkCtr = 0;
    toProc     = '*EXT';
  // ... *PERVIOUS
  when   toStkC = cMsg_Prv;
    callStkCtr = 1;
  // ... *SAME
  when   toStkC = cMsg_Same;
    callStkCtr = 0;
  // ... others
  other;
    callStkCtr = toStkC;
  endsl;

  // To procedure ...
  select;
  // ... *
  when   toProc = cMsg_ToMyself;
    callStkE   = '*';
    // ... add 1 to skip f_sndPgmMsg() stack entry
    callStkCtr = callStkCtr + 1;
  // ... *PGMBDY
  when   toProc = cMsg_ToPgmBdy;
    callStkE   = '*PGMBDY';
  // ... *CTLBDY
  when   toProc = cMsg_ToCtlBdy;
    callStkE   = '*CTLBDY';
  // ... *PGMNAME
  when   toProc = cMsg_ToPgm;
    callStkE   = '*PGMNAME';
  // ... *EXT
  when   toProc = '*EXT';
    callStkE   = '*EXT';
  // ... named procedure
  other;
    callStkE   = toProc;
  endsl;

  // To module ...
  callStkEQ.module  = toMod;

  // To program ...
  callStkEQ.program = toPgm;

  // Set message file name and library ...
  qMsgF.name = i_msg.file;
  qMsgF.lib  = i_msg.lib;

  // Initialize message key ...
  msgKey  = '';

  // Initialize error code ...
  errCode = f_newApiErrCode(cFalse);

  // Finally send the message ...
  QMHSNDPM(i_msg.ID: qMsgF: i_msg.data: %len(%trimR(i_msg.data)):
           i_msg.type: callStkE: callStkCtr: msgKey: errCode:
           %len(%trimR(callStkE)): callStkEQ: -1);

  // Check API error code
  if  f_isApiError(errCode);
    msgKey = '';
    msg    = f_cvtApiErrCodeToMsg(errCode);
  else;
    msg    = f_newMsg(cMsg_ID_OK);
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return   msgKey;


end-proc;

//=========================================================================
//  Receives a program message.
//=========================================================================
//  Parameters:
//   i_msgType     - The type of the message to receive.
//                   Please refer to PBASICS1R1 for a list of valid
//                   message types.
//   i_msgKey      - The key of the message to receive.
//                   Default:        *BLANKS
//   i_action      - The action to take after the message
//                   is received.
//                   Default:        cMsg_Act_Same
//                   cMsg_Act_Old  - Keep message, mark as old.
//                   cMsg_Act_Rmv  - Remove message.
//                   cMsg_Act_Same - Keep message.
//   i_wait        - The time to wait for the message.
//                   Default:        0
//                   0             - Do not wait.
//                   -1            - Wait forever.
//                   n             - Wait n seconds.
//   i_fromStkC    - The stack entry to send the message to.
//                   Default:        cMsg_Same
//                   cMsg_Ext      - The external message queue.
//                   cMsg_Prv      - The procedure that is before
//                                   the procdure that is specified
//                                   at i_toProc.
//                   cMsg_Same     - The procedure that is specified
//                                   at i_toProc.
//   i_fromProc    - The procedure to send the message to.
//                   Default:        cMsg_ToMyself
//                   cMsg_ToMyself - The procedure that calls
//                                   f_rcvPgmMsg().
//   i_fromMod     - The module that contains the procedure.
//                   Default:        *NONE
//   i_fromPgm     - The program that contains the module.
//                   Default:        *NONE
//   o_msg         - The API error message.
//
//  Returns:
//   rcvm0200_t    - Format RCVM0200 of the received message.
//=========================================================================
dcl-proc f_rcvPgmMsg export;
  dcl-pi *n likeds(rcvm0200_t);
    i_msgType  char(10) const;
    i_msgKey   char(4) options(*nopass: *omit) const;
    i_action   char(10) options(*nopass: *omit) const;
    i_wait     int(10) options(*nopass: *omit) const;
    i_fromStkC int(10) options(*nopass: *omit) const;
    i_fromProc char(256) options(*nopass: *omit) const;
    i_fromMod  char(10) options(*nopass: *omit) const;
    i_fromPgm  char(10) options(*nopass: *omit) const;
    o_msg      likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Parameter positions
  dcl-c p_msgKey 2;
  dcl-c p_action 3;
  dcl-c p_wait 4;
  dcl-c p_fromStkC 5;
  dcl-c p_fromProc 6;
  dcl-c p_fromMod 7;
  dcl-c p_fromPgm 8;
  dcl-c p_msg 9;

  //  Optional parameter fields
  dcl-s msgKey like(i_msgKey) inz;
  dcl-s action like(i_action) inz;
  dcl-s wait like(i_wait) inz;
  dcl-s fromStkC like(i_fromStkC) inz;
  dcl-s fromProc like(i_fromProc) inz;
  dcl-s fromMod like(i_fromMod) inz;
  dcl-s fromPgm like(i_fromPgm) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;

  //  Helper fields QMHSNDPM
  dcl-ds rcvm0200 likeds(rcvm0200_t) inz;
  dcl-s callStkE like(i_fromProc) inz;
  dcl-s callStkCtr int(10) inz;
  dcl-ds callStkEQ qualified;
    module  char(10) inz;
    program char(10) inz;
  end-ds;
  dcl-ds errCode likeds(errCode_t) inz;
  //-------------------------------------------------------------------*

  // Process optional parameter values ...
  // ... message key
  if  %parms >= p_msgKey;
    CEETSTA(isPresent: p_msgKey: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    msgKey = i_msgKey;
  else;
    msgKey = '';
  endif;

  // ... action
  if  %parms >= p_action;
    CEETSTA(isPresent: p_action: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    action = i_action;
  else;
    action = cMsg_Act_Same;
  endif;

  // ... wait
  if  %parms >= p_wait;
    CEETSTA(isPresent: p_wait: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    wait = i_wait;
  else;
    wait = 0;            //  Do not wait for the message.
  endif;

  // ... stack counter
  if  %parms >= p_fromStkC;
    CEETSTA(isPresent: p_fromStkC: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromStkC = i_fromStkC;
  else;
    fromStkC = cMsg_Same;
  endif;

  // ... from procedure
  if  %parms >= p_fromProc;
    CEETSTA(isPresent: p_fromProc: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromProc = i_fromProc;
  else;
    fromProc = cMsg_toMySelf;
  endif;

  // ... from module
  if  %parms >= p_fromMod;
    CEETSTA(isPresent: p_fromMod: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromMod  = i_fromMod;
  else;
    fromMod  = '*NONE';
  endif;

  // ... from program
  if  %parms >= p_fromPgm;
    CEETSTA(isPresent: p_fromPgm: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromPgm  = i_fromPgm;
  else;
    fromPgm  = '*NONE';
  endif;

  // Set values to call QMHSNDPM API:
  // Call stack counter ...
  select;
  // ... *EXT
  when   fromStkC = cMsg_Ext;
    callStkCtr = 0;
    fromProc   = '*EXT';
  // ... *PERVIOUS
  when   fromStkC = cMsg_Prv;
    callStkCtr = 1;
  // ... *SAME
  when   fromStkC = cMsg_Same;
    callStkCtr = 0;
  // ... sonst
  other;
    callStkCtr = fromStkC;
  endsl;

  // From procedure ...
  select;
  // ... *
  when   fromProc = cMsg_ToMyself;
    callStkE   = '*';
    // ... add 1 to skip f_rcvPgmMsg() stack entry
    callStkCtr = callStkCtr + 1;
  // ... *EXT
  when   fromProc = '*EXT';
    callStkE   = '*EXT';
  // ... named procedure
  other;
    callStkE   = fromProc;
  endsl;

  // From module ...
  callStkEQ.module  = fromMod;

  // From program ...
  callStkEQ.program = fromPgm;

  // Initialize error code ...
  errCode = f_newApiErrCode(cFalse);

  // Finally receive the message ...
  QMHRCVPM(rcvm0200: %size(rcvm0200): 'RCVM0200': callStkE: callStkCtr:
           i_msgType: msgKey: wait: action: errCode:
           %len(%trimR(callStkE)): callStkEQ);

  // Check API error code
  if  f_isApiError(errCode);
    clear   rcvm0200;
    msg = f_cvtApiErrCodeToMsg(errCode);
  else;
    p_assert(%size(rcvm0200) >= rcvm0200.bytAvl :
             'RCVM0200 too small to hold result');
    msg = f_newMsg(cMsg_ID_OK);
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return   rcvm0200;


end-proc;

//=========================================================================
//  Receives a program message and returns a message structure.
//=========================================================================
//  Parameters:
//   i_msgType     - The type of the message to receive.
//                   Please refer to PBASICS1R1 for a list of valid
//                   message types.
//   i_msgKey      - The key of the message to receive.
//                   Default:        *BLANKS
//   i_action      - The action to take after the message
//                   is received.
//                   Default:        cMsg_Act_Same
//                   cMsg_Act_Old  - Keep message, mark as old.
//                   cMsg_Act_Rmv  - Remove message.
//                   cMsg_Act_Same - Keep message.
//   i_wait        - The time to wait for the message.
//                   Default:        0
//                   0             - Do not wait.
//                   -1            - Wait forever.
//                   n             - Wait n seconds.
//   i_fromStkC    - The stack entry to send the message to.
//                   Default:        cMsg_Same
//                   cMsg_Ext      - The external message queue.
//                   cMsg_Prv      - The procedure that is before
//                                   the procdure that is specified
//                                   at i_toProc.
//                   cMsg_Same     - The procedure that is specified
//                                   at i_toProc.
//   i_fromProc    - The procedure to send the message to.
//                   Default:        cMsg_ToMyself
//                   cMsg_ToMyself - The procedure that calls
//                                   f_rcvPgmMsg().
//   i_fromMod     - The module that contains the procedure.
//                   Default:        *NONE
//   i_fromPgm     - The program that contains the module.
//                   Default:        *NONE
//   o_msg         - The API error message.
//
//  Returns:
//   msg           - Received message.
//=========================================================================
dcl-proc f_rcvPgmMsgObj export;
  dcl-pi *n likeds(msg_t);
    i_msgType  char(10) const;
    i_msgKey   char(4) options(*nopass: *omit) const;
    i_action   char(10) options(*nopass: *omit) const;
    i_wait     int(10) options(*nopass: *omit) const;
    i_fromStkC int(10) options(*nopass: *omit) const;
    i_fromProc char(256) options(*nopass: *omit) const;
    i_fromMod  char(10) options(*nopass: *omit) const;
    i_fromPgm  char(10) options(*nopass: *omit) const;
    o_msg      likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-ds rtnMsg likeds(msg_t) inz;

  //  Parameter positions
  dcl-c p_msgKey 2;
  dcl-c p_action 3;
  dcl-c p_wait 4;
  dcl-c p_fromStkC 5;
  dcl-c p_fromProc 6;
  dcl-c p_fromMod 7;
  dcl-c p_fromPgm 8;
  dcl-c p_msg 9;

  //  Optional parameter fields
  dcl-s fromStkC like(i_fromStkC) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;

  //  Helper fields
  dcl-s callStkCtr int(10) inz;
  dcl-ds rcvm0200 likeds(rcvm0200_t) inz;
  //-------------------------------------------------------------------*

  // Process optional parameter values ...
  // ... stack counter
  if (%parms() >= p_fromStkC);
    CEETSTA(isPresent: p_fromStkC: *omit);
  else;
    isPresent = 0;
  endif;

  if (isPresent = 1);
    fromStkC = i_fromStkC;
  else;
    fromStkC = cMsg_Same;
  endif;

  // Adjust stack counter
  select;
  when (fromStkC = cMsg_Ext);
    callStkCtr = fromStkC;
  // ... *PERVIOUS
  when (fromStkC = cMsg_Prv);
    callStkCtr = 1 + 1;  // let f_rcvPgmMsg() skip f_rcvPgmMsgObj()
  // ... *SAME
  when (fromStkC = cMsg_Same);
    callStkCtr = 0 + 1;  // let f_rcvPgmMsg() skip f_rcvPgmMsgObj()
  // ... everything else
  other;
    callStkCtr = fromStkC + 1;  // let f_rcvPgmMsg() skip f_rcvPgmMsgObj()
  endsl;

  // Receive the message
  select;
  when (%parms() < p_msgKey);    //   1 parameter passed
    rcvm0200 = f_rcvPgmMsg(i_msgType: *omit: *omit: *omit: callStkCtr
                           : *omit: *omit: *omit: msg);

  when (%parms() = p_msgKey);    //   2 parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey: *omit: *omit: callStkCtr
                           : *omit: *omit: *omit: msg);

  when (%parms() = p_action);    //   3 parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey
                           : i_action: *omit: callStkCtr
                           : *omit: *omit: *omit: msg);

  when (%parms() = p_wait);      //   4 parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey
                           : i_action
                           : i_wait: callStkCtr
                           : *omit: *omit: *omit: msg);

  when (%parms() = p_fromStkC);  //   5 parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey
                           : i_action
                           : i_wait
                           : callStkCtr
                           : *omit: *omit: *omit: msg);

  when (%parms() = p_fromProc);  //   6 parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey
                           : i_action
                           : i_wait
                           : callStkCtr
                           : i_fromProc
                           : *omit: *omit: msg);

  when (%parms() = p_fromMod);   //   7 parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey
                           : i_action
                           : i_wait
                           : callStkCtr
                           : i_fromProc
                           : i_fromMod
                           : *omit: msg);

  other;                         //   8 or more parameters passed
    rcvm0200 = f_rcvPgmMsg(i_msgType
                           : i_msgKey
                           : i_action
                           : i_wait
                           : callStkCtr
                           : i_fromProc
                           : i_fromMod
                           : i_fromPgm
                           : msg);
  endsl;

  if (msg.ID = cMSG_ID_OK);
    rtnMsg = f_cvtRcvMsgToMsg(rcvm0200);
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return rtnMsg;


end-proc;

//=========================================================================
//  Removes a program message.
//=========================================================================
//  Parameters:
//   i_msgToRemove - The type of the message to receive.
//                   cMsg_Rmv_All  - Remove all messages.
//                   cMsg_Rmv_ByKey- Remove message that is specified
//                                   by i_msgKey.
//                   cMsg_Rmv_New  - Remove new messages.
//                   cMsg_Rmv_Old  - Remove old messages.
//                   cMsg_Rmv_Scope- Remove the scope message in the
//                                   message key parameter.
//   i_msgKey      - The key of the message to remove.
//                   Default:        *BLANKS
//   i_toStkC      - The stack entry to send the message to.
//                   Default:        cMsg_Same
//                   cMsg_AllInact - All inactive call stack entries.
//                                   i_msgToRemove must be cMsg_Rmv_All.
//                   cMsg_Ext      - The external message queue.
//                   cMsg_Prv      - The procedure that is before
//                                   the procdure that is specified
//                                   at i_toProc.
//                   cMsg_Same     - The procedure that is specified
//                                   at i_toProc.
//   i_toProc      - The procedure to send the message to.
//                   Default:        cMsg_toMySelf
//                   cMsg_ToMyself - The procedure that calls
//                                   f_rcvPgmMsg().
//   i_toMod       - The module that contains the procedure.
//                   Default:        *NONE
//   i_toPgm       - The program that contains the module.
//                   Default:        *NONE
//   o_msg         - The API error message.
//
//  Returns:
//   void
//=========================================================================
dcl-proc p_rmvPgmMsg export;
  dcl-pi *n;
    i_msgToRemove char(10) const;
    i_msgKey      char(4) options(*nopass: *omit) const;
    i_fromStkC    int(10) options(*nopass: *omit) const;
    i_fromProc    char(256) options(*nopass: *omit) const;
    i_fromMod     char(10) options(*nopass: *omit) const;
    i_fromPgm     char(10) options(*nopass: *omit) const;
    o_msg         likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Parameter positions
  dcl-c p_msgKey 2;
  dcl-c p_fromStkC 3;
  dcl-c p_fromProc 4;
  dcl-c p_fromMod 5;
  dcl-c p_fromPgm 6;
  dcl-c p_msg 7;

  //  Optional parameter fields
  dcl-s msgKey like(i_msgKey) inz;
  dcl-s fromStkC like(i_fromStkC) inz;
  dcl-s fromProc like(i_fromProc) inz;
  dcl-s fromMod like(i_fromMod) inz;
  dcl-s fromPgm like(i_fromPgm) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;

  //  Helper fields QMHSNDPM
  dcl-s callStkE like(i_fromProc) inz;
  dcl-s callStkCtr int(10) inz;
  dcl-ds callStkEQ qualified;
    module  char(10) inz;
    program char(10) inz;
  end-ds;
  dcl-ds errCode likeds(errCode_t) inz;
  //-------------------------------------------------------------------*

  // Process optional parameter values ...
  // ... message key
  if  %parms >= p_msgKey;
    CEETSTA(isPresent: p_msgKey: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    msgKey = i_msgKey;
  else;
    msgKey = '';
  endif;

  // ... stack counter
  if  %parms >= p_fromStkC;
    CEETSTA(isPresent: p_fromStkC: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromStkC = i_fromStkC;
  else;
    fromStkC = cMsg_Same;
  endif;

  // ... from procedure
  if  %parms >= p_fromProc;
    CEETSTA(isPresent: p_fromProc: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromProc = i_fromProc;
  else;
    fromProc = cMsg_toMySelf;
  endif;

  // ... from module
  if  %parms >= p_fromMod;
    CEETSTA(isPresent: p_fromMod: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromMod  = i_fromMod;
  else;
    fromMod  = '*NONE';
  endif;

  // ... from program
  if  %parms >= p_fromPgm;
    CEETSTA(isPresent: p_fromPgm: *omit);
  else;
    isPresent = 0;
  endif;

  if  isPresent = 1;
    fromPgm  = i_fromPgm;
  else;
    fromPgm  = '*NONE';
  endif;

  // Set values to call QMHRMVPM API:
  // Call stack counter ...
  select;
  // ... *ALLINACT
  when   fromStkC = cMsg_AllInact;
    callStkCtr = 0;
    fromProc   = '*ALLINACT';
  // ... *EXT
  when   fromStkC = cMsg_Ext;
    callStkCtr = 0;
    fromProc   = '*EXT';
  // ... *PERVIOUS
  when   fromStkC = cMsg_Prv;
    callStkCtr = 1;
  // ... *SAME
  when   fromStkC = cMsg_Same;
    callStkCtr = 0;
  // ... sonst
  other;
    callStkCtr = fromStkC;
  endsl;

  // From procedure ...
  select;
  // ... *
  when   fromProc = cMsg_ToMyself;
    callStkE   = '*';
    // ... add 1 to skip f_rcvPgmMsg() stack entry
    callStkCtr = callStkCtr + 1;
  // ... *EXT
  when   fromProc = '*EXT';
    callStkE   = '*EXT';
  // ... *ALLINACT
  when   fromProc = '*ALLINACT';
    callStkE   = '*ALLINACT';
  // ... named procedure
  other;
    callStkE   = fromProc;
  endsl;

  // From module ...
  callStkEQ.module  = fromMod;

  // From program ...
  callStkEQ.program = fromPgm;

  // Initialize error code ...
  errCode = f_newApiErrCode(cFalse);

  // Finally remove the message ...
  QMHRMVPM(callStkE: callStkCtr: msgKey: i_msgToRemove: errCode:
           %len(%trimR(callStkE)): callStkEQ: '*NO');

  // Check API error code
  if  f_isApiError(errCode);
    msg = f_cvtApiErrCodeToMsg(errCode);
  else;
    msg = f_newMsg(cMsg_ID_OK);
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return;


end-proc;

//=========================================================================
//  Retrieves the message text of a given message.
//  Replaces substitution variables with message data.
//=========================================================================
//  Parameters:
//   i_msg         - The message to retrieve the text from.
//   o_msg         - The API error message.
//
//  Returns:
//   msgText       - The message text that was retrieved from
//                   the given message.
//=========================================================================
dcl-proc f_rtvMsgText export;
  dcl-pi *n varchar(4096);
    i_msg likeds(msg_t) const;
    o_msg likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-s msgText varchar(4096) inz;

  //  Parameter positions
  dcl-c p_msg 2;

  //  Optional parameter fields
  dcl-ds msg likeds(o_msg) inz;

  //  Local fields
  dcl-ds rtvm0100 likeds(rtvm0100_t) based(pRtvm0100);
  dcl-ds qMsgF likeds(qObj_t) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  //-------------------------------------------------------------------*


  // Retrieve message information
  qMsgF.name = i_msg.file;
  qMsgF.lib  = i_msg.lib;
  pRtvm0100  = lf_rtvMsgD('RTVM0100':
                          i_msg.ID: %trimR(i_msg.data): qMsgF: msg:
                          '*YES': '*NO');

  // Retrieve message text from message information
  if   pRtvm0100 <> *NULL;
    if   rtvm0100.lenMsgRet > 0;
      msgText = %subst(rtvm0100: 25: rtvm0100.lenMsgRet);
      xdealloc(pRtvm0100);
    else;
      msgText = '';
    endif;
  else;
    msgText = '';
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return   msgText;


end-proc;

//=========================================================================
//  Retrieves the message help text of a given message.
//  Replaces substitution variables with message data.
//=========================================================================
//  Parameters:
//   i_msg         - The message to retrieve the help text from.
