//=========================================================================
//  Checks object existance.
//=========================================================================
//  Parameters:
//   i_obj         - The object to check for existance.
//   i_lib         - The library that contains the object.
//                   Default:        *LIBL
//   i_type        - The type of the object.
//   i_mbr         - The member that is checked in case of that
//                   the object is a file.
//                   Default:        *NONE
//
//  Returns:
//   doesExists    - Returns cTrue when the object exists.
//=========================================================================

dcl-proc f_exist export;
  dcl-pi *n ind;
    i_obj  char(10) const;
    i_lib  char(10) options(*omit) const;
    i_type char(10) const;
    i_mbr  char(10) options(*nopass) const;
  end-pi;

  //  Return value
  dcl-s doesExist ind inz(cFalse);

  //  Parameter positions
  dcl-c p_lib 2;
  dcl-c p_mbr 4;

  //  Optional parameter fields
  dcl-s lib like(i_lib) inz;
  dcl-s mbr like(i_mbr) inz;

  //  Local fields
  dcl-ds objd0100 likeds(objd0100_t) inz;
  dcl-ds mbrd0100 likeds(mbrd0100_t) inz;
  dcl-ds msg likeds(msg_t) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Process optional parameter values ...
  // ... i_lib
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_lib: *omit);                                                //R
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    lib = i_lib;
  else;
    lib = '*LIBL';
  endif;

  // ... i_mbr
  if   %parms >= p_mbr;
    mbr = i_mbr;
  else;
    mbr = '*NONE';
  endif;

  // Retrieve the object description
  objd0100 = f_rtvObjD(i_obj: lib: i_type: 'OBJD0100': msg);

  // Retrieve member description if object is a file
  // and a member name was given
  if   (msg.ID = cMSG_ID_OK) and (mbr <> '*NONE');
    mbrd0100 = f_rtvMbrD(i_obj: lib: i_mbr: 'MBRD0100': msg);
  endif;

  // Set return value
  if   msg.ID = cMSG_ID_OK;
    doesExist = cTrue;
  else;
    doesExist = cFalse;
  endif;

  return   doesExist;


end-proc;

//=========================================================================
//  Retrieve object description.
//=========================================================================
//  Parameters:
//   i_obj         - The object to retrieve information from.
//   i_lib         - The library that contains the object.
//                   Default:        *LIBL
//   i_type        - The type of the object.
//   i_format      - The format of the object description.
//                   Default:        OBJD0100
//   o_msg         - The API error message.
//
//  Returns:
//   object descr. - Returns the member description of the file member.
//=========================================================================

dcl-proc f_rtvObjD export;
  dcl-pi *n char(1024);
    i_obj    char(10) const;
    i_lib    char(10) options(*omit) const;
    i_type   char(10) const;
    i_format char(8) options(*nopass: *omit) const;
    o_msg    likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-ds objD len(1024) inz qualified;
    bytRet int(10);
    bytAvl int(10) overlay(bytRet);
  end-ds;

  //  Parameter positions
  dcl-c p_lib 2;
  dcl-c p_format 4;
  dcl-c p_msg 5;

  //  Optional parameter fields
  dcl-s lib like(i_lib) inz;
  dcl-s format like(i_format) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Local fields
  dcl-ds qObj likeds(qObj_t) inz;
  dcl-ds errCode likeds(errCode_t) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Process optional parameter values ...
  // ... i_lib
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_lib: *omit);                                                //R
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    lib = i_lib;
  else;
    lib = '*LIBL';
  endif;

  // ... i_format
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_format: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    format = i_format;
  else;
    format = 'OBJD0100';
  endif;

  // Call the retrieve object description API
  qObj.name = i_obj;
  qObj.lib  = i_lib;
  errCode   = f_newApiErrCode(cTrue);
  QUSROBJD(objD: %size(objD): format: qObj: i_type: errCode);

  // Set message value
  msg = f_cvtApiErrCodeToMsg(errCode);

  // Check length of receiver variable
  if   not f_isApiError(errCode);
    p_assert(objD.bytRet <= objD.bytAvl:
             'Length of receiver variable objD is +
              to small to hold result');
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return   objD;


end-proc;

//=========================================================================
//  Retrieve member description.
//=========================================================================
//  Parameters:
//   i_file        - The file that contains the member to retrieve
//                   information from.
//   i_lib         - The library that contains the file.
//                   Default:        *LIBL
//   i_mbr         - The name of the member to retrieve information from.
//   i_format      - The format of the object description.
//                   Default:        OBJD0100
//
//  Returns:
//   object descr. - Returns the object description of the object.
//=========================================================================

dcl-proc f_rtvMbrD export;
  dcl-pi *n char(1024);
    i_file   char(10) const;
    i_lib    char(10) options(*omit) const;
    i_mbr    char(10) const;
    i_format char(8) options(*nopass: *omit) const;
    o_msg    likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-ds mbrD len(1024) inz qualified;
    bytRet int(10);
    bytAvl int(10) overlay(bytRet);
  end-ds;

  //  Parameter positions
  dcl-c p_lib 2;
  dcl-c p_format 4;
  dcl-c p_msg 5;

  //  Optional parameter fields
  dcl-s lib like(i_lib) inz;
  dcl-s format like(i_format) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Local fields
  dcl-ds qFile likeds(qObj_t) inz;
  dcl-ds errCode likeds(errCode_t) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Process optional parameter values ...
  // ... i_lib
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_lib: *omit);                                                //R
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    lib = i_lib;
  else;
    lib = '*LIBL';
  endif;

  // ... i_format
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_format: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    format = i_format;
  else;
    format = 'OBJD0100';
  endif;

  // Call the retrieve object description API
  qFile.name = i_file;
  qFile.lib  = i_lib;
  errCode   = f_newApiErrCode(cTrue);
  QUSRMBRD(mbrD: %size(mbrD): format: qFile: i_mbr: '0': errCode);

  // Set message value
  msg = f_cvtApiErrCodeToMsg(errCode);

  // Check length of receiver variable
  if   not f_isApiError(errCode);
    p_assert(mbrD.bytRet <= mbrD.bytAvl:
             'Length of receiver variable mbrD is +
              to small to hold result');
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return   mbrD;


end-proc;

//=========================================================================
//  Produces a temporary object name.
//=========================================================================
//  Parameters:
//   void
//
//  Returns:
//   qTmpObj       - Returns a qualified temporary object name.
//=========================================================================

dcl-proc f_getTmpName export;
  dcl-pi *n like(qObj_t);
  end-pi;

  //  Return value
  dcl-ds qTmpObj likeds(qObj_t) inz;

  //  Local fields
  dcl-s pTmpNam pointer inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Produce temporary object name
  pTmpNam = tmpnam(*NULL);

  if   pTmpNam <> *NULL;
    qTmpObj.lib  = %str(strtok(pTmpNam: '/'));
    qTmpObj.name = %str(strtok(*NULL  : '/'));
  else;
    clear   qTmpObj;
  endif;

  return   qTmpObj;


end-proc;

//=========================================================================
//  Produces a unique object name.  (experimental)
//=========================================================================
//  Parameters:
//   i_type        - The type of the object.
//   i_lib         - The library that will contain the object.
//
//  Returns:
//   qUnqObj       - Returns a qualified unique object name.
//=========================================================================

dcl-proc f_getUniqueName export;
  dcl-pi *n like(qObj_t);
    i_type char(10) const;
    i_lib  char(10) const;
  end-pi;

  //  Return value
  dcl-ds qUnqObj likeds(qObj_t) inz;

  //  Helper fields
  dcl-s tmStmp timestamp inz;
  dcl-s date date inz;
  dcl-s time time inz;
  dcl-s timeout timestamp inz;
  dcl-s x int(10) inz;
  dcl-ds name qualified;
    longNbr zoned(14);
    julDate zoned(5) overlay(longNbr: *next);
    time    zoned(6) overlay(longNbr: *next);
    mSec    zoned(3) overlay(longNbr: *next);
  end-ds;

  dcl-ds *n;
    chars inz('ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789');
    char  char(1) dim(36) overlay(chars: *next);
  end-ds;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Initialize return value
  clear   qUnqObj;

  // Produce unique object name (max. 1 minute):
  timeout = %timestamp() + %minutes(1);

  dou   (qUnqObj.name <> '') or (%timestamp >= timeOut);

    // Produce unique object name from:
    // Julian date + Time + mSeconds
    tmStmp = %timestamp();
    time   = %time(tmStmp);
    date   = %date(tmStmp);

    name.julDate = %dec(f_val(
                        %char(date: *JUL0)): %size(name.julDate): 0);
    name.time    = %dec(f_val(
                        %char(time: *HMS0)): %size(name.time)   : 0);
    name.mSec    = %subdt(tmStmp: *MSECONDS) / 1000;

    // Set library name
    qUnqObj.lib = i_lib;

    // Encode object name to base 36
    %subst(qUnqObj.name: 1: 1) = 'Z';
    x = 2;
    dou   name.longNbr = 0;
      %subst(qUnqObj.name: x: 1) = char(%rem(name.longNbr: 36) + 1);
      name.longNbr = name.longNbr / 36;
      x = x + 1;
    enddo;

    // Check, if object exists
    if   f_exist(qUnqObj.name: qUnqObj.lib: i_type);
      // Create new name if object exists
      clear   qUnqObj;
    endif;

  enddo;

  p_assert(qUnqObj.name <> '':
           'Unique object name of type ' + %trim(i_type) +
           ' could not be produced'                      );

  return   qUnqObj;


end-proc;

//=========================================================================
//  Creates a user space.
//=========================================================================
//  Parameters:
//   i_usrSpc      - The name of the user space.
//   i_lib         - The library that contains the user space.
//   i_text        - The text description of the user space.
//                   Default:        *BLANKS
//   i_size        - The initial size of the user space.
//                   Default:        65536 (64 kB)
//   i_extAtr      - The extended attribute of the user space.
//                   Default:        *BLANKS
//   i_pubAuth     - The public authority of the user space.
//                   Default:        *USE
//   o_msg         - The API error message.
//
//  Returns:
//   isCreated     - Returns cTrue on success, else cFalse.
//=========================================================================

dcl-proc f_crtUsrSpc export;
  dcl-pi *n ind;
    i_usrSpc  char(10) const;
    i_lib     char(10) const;
    i_text    char(50) options(*omit: *nopass) const;
    i_size    uns(10) options(*omit: *nopass) const;
    i_extAtr  char(10) options(*omit: *nopass) const;
    i_pubAuth char(10) options(*omit: *nopass) const;
    o_msg     likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-s isCreated ind inz(cFalse);

  //  Parameter positions
  dcl-c p_text 3;
  dcl-c p_size 4;
  dcl-c p_extAtr 5;
  dcl-c p_pubAuth 6;
  dcl-c p_msg 7;

  //  Optional parameter fields
  dcl-s text like(i_text) inz;
  dcl-s size like(i_size) inz;
  dcl-s extAtr like(i_extAtr) inz;
  dcl-s pubAuth like(i_pubAuth) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Local fields
  dcl-ds qUsrSpc likeds(qObj_t) inz;
  dcl-ds errCode likeds(errCode_t) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Initialize return value
  isCreated = cFalse;

  // Process optional parameter values ...
  // ... i_text
  if   %parms >= p_text;
    CEETSTA(isPresent: p_text: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    text = i_text;
  else;
    text = '';
  endif;

  // ... i_size
  if   %parms >= p_size;
    CEETSTA(isPresent: p_size: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    size = i_size;
  else;
    size = 64 * 1024;
  endif;

  // ... i_extAtr
  if   %parms >= p_extAtr;
    CEETSTA(isPresent: p_extAtr: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    extAtr = i_extAtr;
  else;
    extAtr = '';
  endif;

  // ... i_pubAuth
  if   %parms >= p_pubAuth;
    CEETSTA(isPresent: p_pubAuth: *omit);
  else;
    isPresent = 0;
  endif;

  if   isPresent = 1;
    pubAuth = i_pubAuth;
  else;
    pubAuth = '*USE';
  endif;

  // Create user space
  qUsrSpc.name = i_usrSpc;
  qUsrSpc.lib  = i_lib;
  errCode      = f_newApiErrCode(cTrue);
  QUSCRTUS(qUsrSpc: extAtr: size: x'00': pubAuth: text: '*NO': errCode);

  // Set return value
  if   f_isApiError(errCode);
    isCreated = cFalse;
    msg       = f_cvtApiErrCodeToMsg(errCode);
  else;
    isCreated = cTrue;
    msg       = f_newMsg(cMSG_ID_OK);
  endif;

  // Process optional/omissible message parameter
  if   %parms >= p_msg;
    CEETSTA(isPresent: p_msg: *omit);
    if   isPresent = 1;
      o_msg = msg;
    endif;
  else;
    if   msg.ID <> cMSG_ID_OK;
      f_sndPgmMsg(msg: cMsg_Prv);
    endif;
  endif;

  return   isCreated;


end-proc;

//=========================================================================
//  Retrieves a pointer to the content of a user space.
//=========================================================================
//  Parameters:
//   i_usrSpc      - The name of the user space.
//   i_lib         - The library that contains the user space.
//                   Default:        *LIBL
//   o_msg         - The API error message.
//
//  Returns:
//   pUsrSpc       - Returns a pointer to the content of a user space
//                   on success, else a NULL pointer.
//=========================================================================

dcl-proc f_rtvUsrSpcPtr export;
  dcl-pi *n pointer;
    i_usrSpc char(10) const;
    i_lib    char(10) options(*nopass: *omit) const;
    o_msg    likeds(msg_t) options(*nopass: *omit);
  end-pi;

  //  Return value
  dcl-s pUsrSpc pointer inz;

  //  Parameter positions
  dcl-c p_lib 2;
  dcl-c p_msg 3;

  //  Optional parameter fields
  dcl-s lib like(i_lib) inz;
  dcl-ds msg likeds(o_msg) inz;

  //  Local fields
  dcl-ds qUsrSpc likeds(qObj_t) inz;
  dcl-ds errCode likeds(errCode_t) inz;

  //  Helper fields CEETSTA
  dcl-s isPresent int(10) inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Initialize return value
  pUsrSpc = *NULL;

  // Process optional parameter values ...
  // ... i_lib
  if   %parms >= p_lib;
    CEETSTA(isPresent: p_lib: *omit);
  else;
