dcl-c cMD5_ONLY 17; //    1 +   16
dcl-c cMD5_FIRST 18; //    2 +   16
dcl-c cMD5_MIDDLE 20; //    4 +   16
dcl-c cMD5_FINAL 24; //    8 +   16

dcl-ds md5_t qualified;
  length uns(5);
  value  char(32);
end-ds;

//  Generate SHA-1:
