dcl-pi PGM_ENTRY_POINT;
  gi_year  packed(15: 5) options(*nopass) const;
  gi_month packed(15: 5) options(*nopass) const;
  gi_day   packed(15: 5) options(*nopass) const;
end-pi;
// - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

if (%parms() >= 3);
  main(gi_year: gi_month: gi_day);
else;
