//    CALL PGM(TEST_RH_01)                                       *
//===============================================================*
//   >>PRE-COMPILER<<                                            *
//     >>CRTCMD<<  CRTRPGMOD    MODULE(&LI/&OB) +                *
//                              SRCFILE(&SL/&SF) +               *
//                              SRCMBR(&SM);                     *
