//===============================================================*
//  Program Entry Point
//===============================================================*
dcl-pi PGM_ENTRY_POINT;
  gi_boolean char(1) options(*nopass) const;
end-pi;

//  Local helper fields
dcl-ds msg likeds(msg_t) inz;
dcl-s procedure char(256) inz;
// - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

procedure = f_this();
msg = f_newMsg(cMSG_ID_NONE: '=> ' + '*N/'
                                   + '*N' + '.'
                                   + %trimR(procedure));
f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);

if (%parms() >= %parmNum(gi_boolean));
  main(gi_boolean);
else;
  main(*on);
endif;

*inlr = *on;

return;


//===============================================================*
//  Main procedure
//===============================================================*
dcl-proc main;
  dcl-pi *n;
    i_boolean ind const;
  end-pi;

  //  Local helper fields
  dcl-ds msg likeds(msg_t) inz;
  dcl-s procedure char(256) inz;
  dcl-s module char(10) inz;
  dcl-s program char(10) inz;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  procedure = f_this();
  msg = f_newMsg(cMSG_ID_NONE: '=> ' + '*N/'
                                     + '*N' + '.'
                                     + %trimR(procedure));
  f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);

  procedure = f_this(module);
  msg = f_newMsg(cMSG_ID_NONE: '=> ' + '*N/'
                                     + %trimR(module) + '.'
                                     + %trimR(procedure));
  f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);

  procedure = f_this(module: program);
  msg = f_newMsg(cMSG_ID_NONE: '=> ' + %trimR(program) + '/'
                                     + %trimR(module) + '.'
                                     + %trimR(procedure));
  f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);

  procedure = f_caller(module: program);
  msg = f_newMsg(cMSG_ID_NONE: '=> ' + %trimR(program) + '/'
                                     + %trimR(module) + '.'
                                     + %trimR(procedure));
  f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);

  p_assert(i_boolean                        :                                          //RADDAT
           'Error detected by p_assert()'   );

  return;


end-proc main;

