  dcl-ds st_stat likeds(st_stat_t) inz;
  dcl-ds msg likeds(msg_t) inz;
  dcl-ds elapsedTime qualified;
    start timestamp inz;
    end   timestamp inz;
  end-ds;
  // - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -

  // Generate a CRC32 checksum of a given stream file:

  // Open stream file
  hFile = open(i_path: O_RDONLY);
  if hFile = RC_ERROR;
    return;
